request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?midNorm ?midOrig ?name WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model tai:normalizedId ?midNorm . }
  OPTIONAL { ?model tai:originalId ?midOrig . }
  OPTIONAL { ?model bbo:name ?name . }
  FILTER( (
    ?midNorm = "1cd93309017949fdbebf0f7d7ea50b4a"
  ) || (
    ?midOrig = "1cd93309017949fdbebf0f7d7ea50b4a"
  ) )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?msgFlow ?msgName ?msgRef ?srcRef ?tgtRef WHERE {
  ?model a bboExt:Model ;
         tai:originalId "1cd93309017949fdbebf0f7d7ea50b4a" .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  ?node tai:belongsTo ?choreo ;
        bbo:name "Car is returned" .

  ?msgFlow a bboExt:MessageFlow ;
           tai:belongsTo ?choreo ;
           bboExt:sourceRef ?srcRef ;
           bboExt:targetRef ?tgtRef .

  FILTER( (STR(?srcRef) = STRENDS(STR(?node), "")) || (STR(?tgtRef) = STRENDS(STR(?node), "")) )

  OPTIONAL {
    ?msgFlow bboExt:messageRef ?msgRef .
    FILTER(BOUND(?msgRef))
    ?message tai:belongsTo ?choreo ;
             bbo:name ?msgName ;
             bbo:id ?msgRef .
  }
}
LIMIT 25
